// ============================================================================
// Root Store
// ============================================================================

export class RootStore {
  user: UserStore
  buildingType: BuildingTypeStore
  building: BuildingStore
  floor: FloorStore
  room: RoomStore
  itemType: ItemTypeStore
  installationItem: InstallationItemStore
  workflowStep: WorkflowStepStore
  workflowTemplate: WorkflowTemplateStore
  workflowTemplateStep: WorkflowTemplateStepStore
  roomItemTemplate: RoomItemTemplateStore

  constructor() {
    this.user = new UserStore()
    this.buildingType = new BuildingTypeStore()
    this.building = new BuildingStore()
    this.floor = new FloorStore()
    this.room = new RoomStore()
    this.itemType = new ItemTypeStore()
    this.installationItem = new InstallationItemStore()
    this.workflowStep = new WorkflowStepStore()
    this.workflowTemplate = new WorkflowTemplateStore()
    this.workflowTemplateStep = new WorkflowTemplateStepStore()
    this.roomItemTemplate = new RoomItemTemplateStore()
    makeAutoObservable(this)
  }

  /** Clear all stores */
  clearAll() {
    this.user.clear()
    this.buildingType.clear()
    this.building.clear()
    this.floor.clear()
    this.room.clear()
    this.itemType.clear()
    this.installationItem.clear()
    this.workflowStep.clear()
    this.workflowTemplate.clear()
    this.workflowTemplateStep.clear()
    this.roomItemTemplate.clear()
  }
}

// ============================================================================
// Factory & Singleton
// ============================================================================

let rootStore: RootStore | null = null

/**
 * Get or create the root store singleton
 */
export function getStore(): RootStore {
  if (!rootStore) {
    rootStore = new RootStore()
  }
  return rootStore
}

/**
 * Create a new root store (for testing or SSR)
 */
export function createStore(): RootStore {
  return new RootStore()
}

/**
 * Reset the singleton store
 */
export function resetStore(): void {
  rootStore = null
}
